def run_command(
    cmd: List[str],
    cwd: Optional[Path] = None,
    capture: bool = True,
    check: bool = True,
) -> subprocess.CompletedProcess:
    """Execute a shell command with logging."""
    logger.debug("Running: %s", " ".join(cmd))
    try:
        result = subprocess.run(
            cmd,
            cwd=cwd,
            capture_output=capture,
            text=True,
            check=check,
        )
        if result.stdout:
            logger.debug("stdout: %s", result.stdout.strip())
        return result
    except subprocess.CalledProcessError as exc:
        logger.error("Command failed: %s", " ".join(cmd))
        if exc.stderr:
            logger.error("stderr: %s", exc.stderr.strip())
        raise


def ensure_tool_installed(tool: str, install_cmd: Optional[List[str]] = None) -> bool:
    """Check that a CLI tool is available, optionally installing it."""
    try:
        run_command([tool, "--version"])
        return True
    except FileNotFoundError:
        if install_cmd:
            logger.info("Installing %s …", tool)
            run_command(install_cmd)
            return True
        logger.error("%s is not installed. Please install it first.", tool)
        return False


def compute_file_hash(path: Path, algorithm: str = "sha256") -> str:
    """Return the hex digest of a file."""
    h = hashlib.new(algorithm)
    with open(path, "rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            h.update(chunk)
    return h.hexdigest()


