@dataclass
class LockedDependency:
    """Represents a single pinned dependency."""
    name: str
    version: str
    hashes: List[str] = field(default_factory=list)
    is_direct: bool = False
    extras: List[str] = field(default_factory=list)


def parse_requirements_txt(path: Path) -> List[LockedDependency]:
    """Parse a pip-compile generated requirements.txt."""
    deps: List[LockedDependency] = []
    if not path.exists():
        return deps

    current_hashes: List[str] = []
    with open(path) as f:
        for raw_line in f:
            line = raw_line.strip()
            if not line or line.startswith("#") or line.startswith("-"):
                # Detect "via" comments to guess direct deps
                continue

            # Collect hashes on continuation lines
            hash_match = re.match(r"--hash=(\S+)", line)
            if hash_match:
                current_hashes.append(hash_match.group(1))
                continue

            # Package line: name==version [; markers] [\]
            pkg_match = re.match(
                r"^([a-zA-Z0-9_.-]+)(?:\[([a-zA-Z0-9_,.-]+)\])?==([^\s;\\]+)",
                line,
            )
            if pkg_match:
                # Flush previous hashes if any
                if deps and not deps[-1].hashes and current_hashes:
                    deps[-1].hashes = current_hashes
                    current_hashes = []

                name = pkg_match.group(1)
                extras = pkg_match.group(2).split(",") if pkg_match.group(2) else []
                version = pkg_match.group(3)

                # Inline hashes
                inline_hashes = re.findall(r"--hash=(\S+)", line)
                deps.append(LockedDependency(
                    name=name,
                    version=version,
                    hashes=inline_hashes,
                    extras=extras,
                ))

    # Flush trailing hashes
    if deps and not deps[-1].hashes and current_hashes:
        deps[-1].hashes = current_hashes

    return deps


def parse_poetry_lock(path: Path) -> List[LockedDependency]:
    """Parse a poetry.lock file (TOML format)."""
    deps: List[LockedDependency] = []
    if not path.exists():
        return deps

    try:
        import tomllib  # Python 3.11+
    except ModuleNotFoundError:
        try:
            import tomli as tomllib  # type: ignore[no-redef]
        except ModuleNotFoundError:
            logger.error("tomllib / tomli not available – cannot parse poetry.lock")
            return deps

    with open(path, "rb") as f:
        data = tomllib.load(f)

    for pkg in data.get("package", []):
        hashes: List[str] = []
        files = pkg.get("files", []) or []  # May be a separate metadata section
        # In newer poetry.lock the hashes live under [[package]] → files
        # which is a list of {file = "...", hash = "sha256:..."}
        if isinstance(files, list):
            for file_entry in files:
                if isinstance(file_entry, dict) and "hash" in file_entry:
                    hashes.append(file_entry["hash"])

        deps.append(LockedDependency(
            name=pkg["name"],
            version=pkg["version"],
            hashes=hashes,
        ))

    return deps


