class DependencyManager:
    """Orchestrates dependency lock-file operations."""

    def __init__(self, config: Optional[ProjectConfig] = None):
        self.config = config or ProjectConfig()
        self._ensure_directories()

    # -- helpers --

    def _ensure_directories(self) -> None:
        for attr in ("requirements_in", "requirements_dev_in", "requirements_test_in", "requirements_prod_in"):
            path: Path = getattr(self.config, attr)
            path.parent.mkdir(parents=True, exist_ok=True)

    def _pip_compile_cmd(
        self,
        src: Path,
        out: Path,
        *,
        upgrade: bool = False,
        upgrade_package: Optional[str] = None,
    ) -> List[str]:
        """Build the pip-compile invocation."""
        cmd = [
            sys.executable, "-m", "piptools", "compile",
            "--strip-extras",
            "--no-header",
            "--annotate",
            "--resolver=backtracking",
            f"--output-file={out}",
        ]
        if self.config.generate_hashes:
            cmd.append("--generate-hashes")
        if self.config.allow_unsafe:
            cmd.append("--allow-unsafe")
        if upgrade:
            cmd.append("--upgrade")
        if upgrade_package:
            cmd.append(f"--upgrade-package={upgrade_package}")
        for host in self.config.trusted_hosts:
            cmd.extend(["--trusted-host", host])
        for url in self.config.extra_index_urls:
            cmd.extend(["--extra-index-url", url])
        cmd.append(str(src))
        return cmd

    # -- public API --

    def init_project(self) -> None:
        """
        Scaffold the dependency file structure.

        For pip-tools:
            requirements/
                base.in       – direct production deps
                dev.in        – development deps (includes base.in)
                test.in       – test/CI deps (includes base.in)
                prod.in       – production extras (includes base.in)

        For poetry:
            pyproject.toml    – with dependency groups
        """
        if self.config.lock_method == LockMethod.PIP_TOOLS:
            self._init_pip_tools()
        elif self.config.lock_method == LockMethod.POETRY:
            self._init_poetry()
        else:
            raise NotImplementedError(f"Init not implemented for {self.config.lock_method}")

    def _init_pip_tools(self) -> None:
        ensure_tool_installed(
            "pip-compile",
            install_cmd=[sys.executable, "-m", "pip", "install", "pip-tools"],
        )

        files_and_templates = [
            (self.config.requirements_in, BASE_IN_TEMPLATE),
            (self.config.requirements_dev_in, DEV_IN_TEMPLATE),
            (self.config.requirements_test_in, TEST_IN_TEMPLATE),
            (self.config.requirements_prod_in, PROD_IN_TEMPLATE),
        ]
        for path, template in files_and_templates:
            if path.exists():
                logger.info("Skipping %s (already exists)", path)
            else:
                path.parent.mkdir(parents=True, exist_ok=True)
                path.write_text(template)
                logger.info("Created %s", path)

        # Save manager config alongside
        config_path = self.config.project_root / ".depmanager.json"
        self.config.save(config_path)
        logger.info(
            "\n✅  Project initialised with pip-tools layout.\n"
            "   Edit the .in files under requirements/, then run:\n"
            "       python dependency_manager.py generate --method pip-tools\n"
        )

    def _init_poetry(self) -> None:
        ensure_tool_installed(
            "poetry",
            install_cmd=[sys.executable, "-m", "pip", "install", "poetry"],
        )
        if self.config.pyproject_toml.exists():
            logger.info("pyproject.toml already exists – skipping scaffold.")
        else:
            content = PYPROJECT_TEMPLATE.replace("{python_version}", self.config.python_version)
            self.config.pyproject_toml.write_text(content)
            logger.info("Created %s", self.config.pyproject_toml)

        config_path = self.config.project_root / ".depmanager.json"
        self.config.save(config_path)
        logger.info(
            "\n✅  Project initialised with Poetry.\n"
            "   Edit pyproject.toml, then run:\n"
            "       python dependency_manager.py generate --method poetry\n"
        )

    # -- generate -----------------------------------------------------------

    def generate(self) -> None:
        """
        Generate / regenerate all lock files from the .in specs (pip-tools)
        or pyproject.toml (Poetry).
        """
        if self.config.lock_method == LockMethod.PIP_TOOLS:
            self._generate_pip_tools()
        elif self.config.lock_method == LockMethod.POETRY:
            self._generate_poetry()
        else:
            raise NotImplementedError(f"Generate not implemented for {self.config.lock_method}")

    def _generate_pip_tools(self) -> None:
        ensure_tool_installed(
            "pip-compile",
            install_cmd=[sys.executable, "-m", "pip", "install", "pip-tools"],
        )

        pairs = [
            (self.config.requirements_in, self.config.requirements_txt),
            (self.config.requirements_dev_in, self.config.requirements_dev_txt),
            (self.config.requirements_test_in, self.config.requirements_test_txt),
            (self.config.requirements_prod_in, self.config.requirements_prod_txt),
        ]
        for src, out in pairs:
            if not src.exists():
                logger.warning("Skipping %s (file not found)", src)
                continue
            logger.info("Compiling %s → %s", src, out)
            cmd = self._pip_compile_cmd(src, out)
            run_command(cmd, cwd=self.config.project_root)
            logger.info("  ✔ %s generated (%d bytes)", out, out.stat().st_size)

        self._stamp_lockfiles()
        logger.info("\n✅  All lock files generated successfully.")

    def _generate_poetry(self) -> None:
        ensure_tool_installed("poetry")
        logger.info("Running poetry lock …")
        run_command(["poetry", "lock", "--no-update"], cwd=self.config.project_root, check=False)
        # --no-update keeps existing resolutions; omit for fresh resolve
        run_command(["poetry", "lock"], cwd=self.config.project_root)
        self._stamp_lockfiles()
        logger.info("\n✅  poetry.lock generated successfully.")

    def _stamp_lockfiles(self) -> None:
        """Write a small metadata file tracking when locks were last generated."""
        stamp = {
            "generated_at": datetime.utcnow().isoformat() + "Z",
            "method": self.config.lock_method.value,
            "python_version": self.config.python_version,
        }
        # Record hashes of each lock file for later verification
        lock_files: List[Path] = []
        if self.config.lock_method == LockMethod.PIP_TOOLS:
            lock_files = [
                self.config.requirements_txt,
                self.config.requirements_dev_txt,
                self.config.requirements_test_txt,
                self.config.requirements_prod_txt,
            ]
        elif self.config.lock_method == LockMethod.POETRY:
            lock_files = [self.config.poetry_lock]

        stamp["files"] = {}
        for lf in lock_files:
            if lf.exists():
                stamp["files"][str(lf)] = compute_file_hash(lf)

        stamp_path = self.config.project_root / ".lockstamp.json"
        with open(stamp_path, "w") as f:
            json.dump(stamp, f, indent=2)
        logger.debug("Lock stamp written to %s", stamp_path)

    # -- update -------------------------------------------------------------

    def update(self, package: Optional[str] = None) -> None:
        """
        Update lock files.

        If *package* is given, only that package (and its dependants) are
        upgraded.  Otherwise every dependency is upgraded to the latest
        version allowed by the .in constraints.
        """
        if self.config.lock_method == LockMethod.PIP_TOOLS:
            self._update_pip_tools(package)
        elif self.config.lock_method == LockMethod.POETRY:
            self._update_poetry(package)
        else:
            raise NotImplementedError

    def _update_pip_tools(self, package: Optional[str]) -> None:
        ensure_tool_installed(
            "pip-compile",
            install_cmd=[sys.executable, "-m", "pip", "install", "pip-tools"],
        )
        pairs = [
            (self.config.requirements_in, self.config.requirements_txt),
            (self.config.requirements_dev_in, self.config.requirements_dev_txt),
            (self.config.requirements_test_in, self.config.requirements_test_txt),
            (self.config.requirements_prod_in, self.config.requirements_prod_txt),
        ]
        for src, out in pairs:
            if not src.exists():
                continue
            logger.info("Updating %s → %s%s", src, out, f" (package={package})" if package else "")
            cmd = self._pip_compile_cmd(
                src,
                out,
                upgrade=package is None,
                upgrade_package=package,
            )
            run_command(cmd, cwd=self.config.project_root)
            logger.info("  ✔ %s updated", out)

        self._stamp_lockfiles()
        logger.info("\n✅  Lock files updated.")

    def _update_poetry(self, package: Optional[str]) -> None:
        ensure_tool_installed("poetry")
        if package:
            logger.info("Updating %s in poetry.lock …", package)
            run_command(["poetry", "update", package], cwd=self.config.project_root)
        else:
            logger.info("Updating all dependencies in poetry.lock …")
            run_command(["poetry", "update"], cwd=self.config.project_root)
        self._stamp_lockfiles()
        logger.info("\n✅  poetry.lock updated.")

    # -- verify -------------------------------------------------------------

    def verify(self) -> bool:
        """
        Verify that the lock files are consistent with the input specs
        and that no lock file has been manually tampered with.

        Returns True if everything checks out.
        """
        ok = True

        # 1. Check stamp freshness
        stamp_path = self.config.project_root / ".lockstamp.json"
        if not stamp_path.exists():
            logger.warning("No .lockstamp.json found – run 'generate' first.")
            ok = False
        else:
            with open(stamp_path) as f:
                stamp = json.load(f)
            for path_str, expected_hash in stamp.get("files", {}).items():
                p = Path(path_str)
                if not p.exists():
                    logger.error("Lock file missing: %s", p)
                    ok = False
                    continue
                actual = compute_file_hash(p)
                if actual != expected_hash:
                    logger.error(
                        "Lock file %s has been modified since last generation!\n"
                        "  expected sha256: %s\n"
                        "  actual   sha256: %s",
                        p, expected_hash, actual,
                    )
                    ok = False

        # 2. For pip-tools, run pip-compile --dry-run and compare
        if self.config.lock_method == LockMethod.PIP_TOOLS:
            ok = self._verify_pip_tools() and ok

        # 3. For Poetry, run poetry check
        if self.config.lock_method == LockMethod.POETRY:
            ok = self._verify_poetry() and ok

        if ok:
            logger.info("\n✅  All lock files are consistent and verified.")
        else:
            logger.error("\n❌  Lock file verification FAILED. See errors above.")
        return ok

    def _verify_pip_tools(self) -> bool:
        ok = True
        pairs = [
            (self.config.requirements_in, self.config.requirements_txt),
        ]
        for src, out in pairs:
            if not src.exists() or not out.exists():
                continue
            with tempfile.NamedTemporaryFile(suffix=".txt", delete=False) as tmp:
                tmp_path = Path(tmp.name)
            try:
                cmd = self._pip_compile_cmd(src, tmp_path)
                run_command(cmd, cwd=self.config.project_root)
                # Compare
                expected = out.read_text().strip()
                actual = tmp_path.read_text().strip()
                if expected != actual:
                    logger.warning(
                        "%s is out of date with respect to %s.\n"
                        "Run 'generate' to refresh.",
                        out, src,
                    )
                    ok = False
                else:
                    logger.info("  ✔ %s is up-to-date with %s", out, src)
            finally:
                tmp_path.unlink(missing_ok=True)
        return ok

    def _verify_poetry(self) -> bool:
        result = run_command(
            ["poetry", "check", "--lock"],
            cwd=self.config.project_root,
            check=False,
        )
        if result.returncode != 0:
            logger.error("poetry check --lock failed")
            return False
        logger.info("  ✔ poetry.lock is consistent with pyproject.toml")
        return True

    # -- sync (install) -----------------------------------------------------

    def sync(self, env: Environment = Environment.DEVELOPMENT) -> None:
        """
        Install exactly the locked dependencies into the current environment.
        """
        if self.config.lock_method == LockMethod.PIP_TOOLS:
            self._sync_pip_tools(env)
        elif self.config.lock_method == LockMethod.POETRY:
            self._sync_poetry(env)

    def _sync_pip_tools(self, env: Environment) -> None:
        ensure_tool_installed(
            "pip-sync",
            install_cmd=[sys.executable, "-m", "pip", "install", "pip-tools"],
        )
        env_map = {
            Environment.DEVELOPMENT: self.config.requirements_dev_txt,
            Environment.TESTING: self.config.requirements_test_txt,
            Environment.STAGING: self.config.requirements_prod_txt,
            Environment.PRODUCTION: self.config.requirements_prod_txt,
        }
        req_file = env_map.get(env, self.config.requirements_txt)
        if not req_file.exists():
            logger.error("Lock file %s not found – run 'generate' first.", req_file)
            return
        logger.info("Syncing environment to %s …", req_file)
        run_command(
            [sys.executable, "-m", "piptools", "sync", str(req_file)],
            cwd=self.config.project_root,
        )
        logger.info("\n✅  Environment synced to %s.", req_file)

    def _sync_poetry(self, env: Environment) -> None:
        ensure_tool_installed("poetry")
        cmd = ["poetry", "install"]
        if env == Environment.PRODUCTION:
            cmd.append("--only=main")
        elif env == Environment.TESTING:
            cmd.extend(["--with", "test"])
        else:
            cmd.append("--with=dev,test")
        cmd.append("--sync")
        logger.info("Running: %s", " ".join(cmd))
        run_command(cmd, cwd=self.config.project_root)
        logger.info("\n✅  Poetry environment synced for %s.", env.value)

    # -- audit --------------------------------------------------------------

    def audit(self) -> bool:
        """
        Run a security audit against known vulnerability databases.
        Uses pip-audit (recommended) or safety.
        """
        logger.info("Running dependency security audit …")

        # Try pip-audit first
        try:
            ensure_tool_installed(
                "pip-audit",
                install_cmd=[sys.executable, "-m", "pip", "install", "pip-audit"],
            )
            req_file = self.config.requirements_txt
            if self.config.lock_method == LockMethod.POETRY:
                # Export requirements first
                req_file = self.config.project_root / "requirements-audit.txt"
                run_command(
                    ["poetry", "export", "-f", "requirements.txt", "--output", str(req_file)],
                    cwd=self.config.project_root,
                )

            if req_file.exists():
                result = run_command(
                    [sys.executable, "-m", "pip_audit", "-r", str(req_file), "--desc"],
                    cwd=self.config.project_root,
                    check=False,
                )
                if result.returncode != 0:
                    logger.error("\n❌  Vulnerabilities found! Review output above.")
                    return False
                logger.info("\n✅  No known vulnerabilities detected.")
                return True
            else:
                logger.warning("No requirements file found for audit.")
                return False
        except Exception as exc:
            logger.warning("pip-audit failed (%s), trying safety …", exc)

        # Fallback: safety
        try:
            ensure_tool_installed(
                "safety",
                install_cmd=[sys.executable, "-m", "pip", "install", "safety"],
            )
            result = run_command(
                ["safety", "check", "--full-report"],
                cwd=self.config.project_root,
                check=False,
            )
            if result.returncode != 0:
                logger.error("\n❌  Vulnerabilities found!")
                return False
            logger.info("\n✅  No known vulnerabilities detected.")
            return True
        except Exception:
            logger.error("Neither pip-audit nor safety could run.")
            return False

    # -- report -------------------------------------------------------------

    def report(self) -> None:
        """Print a summary of all locked dependencies."""
        logger.info("=" * 72)
        logger.info("DEPENDENCY REPORT")
        logger.info("=" * 72)

        all_deps: Dict[str, List[LockedDependency]] = {}

        if self.config.lock_method == LockMethod.PIP_TOOLS:
            files = {
                "base": self.config.requirements_txt,
                "dev": self.config.requirements_dev_txt,
                "test": self.config.requirements_test_txt,
                "prod": self.config.requirements_prod_txt,
            }
            for label, path in files.items():
                if path.exists():
                    deps = parse_requirements_txt(path)
                    all_deps[label] = deps
        elif self.config.lock_method == LockMethod.POETRY:
            if self.config.poetry_lock.exists():
                all_deps["poetry"] = parse_poetry_lock(self.config.poetry_lock)

        total_unique: Set[str] = set()
        for label, deps in all_deps.items():
            logger.info("\n--- %s (%d packages) ---", label, len(deps))
            for dep in sorted(deps, key=lambda d: d.name.lower()):
                hash_info = f"  [{len(dep.hashes)} hash(es)]" if dep.hashes else "  [NO HASHES]"
                logger.info("  %-40s %s%s", dep.name, dep.version, hash_info)
                total_unique.add(dep.name.lower())

        logger.info("\n" + "=" * 72)
        logger.info("Total unique packages across all environments: %d", len(total_unique))

        # Check for version divergence across environments
        version_map: Dict[str, Dict[str, str]] = {}
        for label, deps in all_deps.items():
            for dep in deps:
                version_map.setdefault(dep.name.lower(), {})[label] = dep.version

        divergent = {
            name: versions
            for name, versions in version_map.items()
            if len(set(versions.values())) > 1
        }
        if divergent:
            logger.warning("\n⚠️  Version divergence detected across environments:")
            for name, versions in sorted(divergent.items()):
                logger.warning("  %s: %s", name, dict(versions))
        else:
            logger.info("\n✅  No version divergence across environments.")

    # -- virtual environment ------------------------------------------------

    def create_venv(self) -> None:
        """Create a virtual environment if one does not exist."""
        venv = self.config.venv_path
        if venv.exists():
            logger.info("Virtual environment already exists at %s", venv)
            return
        logger.info("Creating virtual environment at %s …", venv)
        run_command([sys.executable, "-m", "venv", str(venv)])
        logger.info("✅  Virtual environment created. Activate with:")
        if os.name == "nt":
            logger.info("    %s\\Scripts\\activate", venv)
        else:
            logger.info("    source %s/bin/activate", venv)


# ---------------------------------------------------------------------------
# CI/CD helper: verify-or-fail
# ---------------------------------------------------------------------------

def ci_verify(config: ProjectConfig) -> None:
    """
    Intended for CI pipelines.  Verifies lock files are consistent and
    exits with a non-zero code on failure.

    Example GitHub Actions step:
        - name: Verify lock files
          run: python dependency_manager.py verify --strict
    """
    mgr = DependencyManager(config)
    if not mgr.verify():
        logger.error(
            "Lock files are inconsistent or stale.\n"
            "Please run 'python dependency_manager.py generate' locally and commit the result."
        )
        sys.exit(1)


# ---------------------------------------------------------------------------
# CLI
# ---------------------------------------------------------------------------

def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(
        description="Manage Python dependency lock files for consistent environments.",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog=textwrap.dedent("""\
            Examples
            --------
            # First-time setup (pip-tools)
            %(prog)s init --method pip-tools

            # Generate lock files from .in specs
            %(prog)s generate --method pip-tools

            # Update a single package
            %(prog)s update requests

            # Update everything
            %(prog)s update

            # Install exactly the locked deps (dev)
            %(prog)s sync --env development

            # Verify in CI
            %(prog)s verify --strict

            # Security audit
            %(prog)s audit

            # Human-readable report
            %(prog)s report

            Best Practices
            ---------------
            1. Commit ALL lock files (.txt / poetry.lock) to version control.
            2. Never edit lock files by hand – always regenerate.
            3. Use 'verify' in CI to catch stale lock files.
            4. Run 'audit' regularly (weekly cron or pre-release).
            5. Use separate dependency groups for dev / test / prod.
            6. Enable hash checking (--generate-hashes) for supply-chain security.
            7. Review dependency diffs in pull requests carefully.
        """),
    )

    parser.add_argument(
        "--config",
        type=Path,
        default=Path(".depmanager.json"),
        help="Path to configuration file (default: .depmanager.json)",
    )
    parser.add_argument(
        "--verbose", "-v",
        action="store_true",
        help="Enable debug logging",
    )

    sub = parser.add_subparsers(dest="command", help="Command to run")

    # init
    p_init = sub.add_parser("init", help="Scaffold dependency file structure")
    p_init.add_argument("--method", type=LockMethod, default=LockMethod.PIP_TOOLS, choices=list(LockMethod))
    p_init.add_argument("--python-version", default="3.11")
    p_init.add_argument("--no-hashes", action="store_true", help="Disable hash generation")

    # generate
    p_gen = sub.add_parser("generate", help="Generate / regenerate lock files")
    p_gen.add_argument("--method", type=LockMethod, default=None, choices=list(LockMethod))

    # update
    p_upd = sub.add_parser("update", help="Update lock files (optionally a single package)")
    p_upd.add_argument("package", nargs="?", default=None, help="Package to update (omit for all)")
    p_upd.add_argument("--method", type=LockMethod, default=None, choices=list(LockMethod))

    # verify
    p_ver = sub.add_parser("verify", help="Verify lock files are consistent")
    p_ver.add_argument("--strict", action="store_true", help="Exit non-zero on failure (CI mode)")

    # sync
    p_sync = sub.add_parser("sync", help="Install locked dependencies into current env")
    p_sync.add_argument("--env", type=Environment, default=Environment.DEVELOPMENT, choices=list(Environment))

    # audit
    sub.add_parser("audit", help="Security audit of locked dependencies")

    # report
    sub.add_parser("report", help="Print dependency summary report")

    # venv
    sub.add_parser("venv", help="Create a virtual environment")

    return parser


def main() -> None:
    parser = build_parser()
    args = parser.parse_args()

    if args.verbose:
        logging.getLogger().setLevel(logging.DEBUG)

    if not args.command:
        parser.print_help()
        sys.exit(0)

    # Load config
    config = ProjectConfig.from_file(args.config)

    # Override method if specified on command line
    if hasattr(args, "method") and args.method is not None:
        config.lock_method = args.method

    if hasattr(args, "python_version") and args.python_version:
        config.python_version = args.python_version

    if hasattr(args, "no_hashes") and args.no_hashes:
        config.generate_hashes = False

    mgr = DependencyManager(config)

    if args.command == "init":
        mgr.init_project()

    elif args.command == "generate":
        mgr.generate()

    elif args.command == "update":
        mgr.update(package=args.package)

    elif args.command == "verify":
        success = mgr.verify()
        if args.strict and not success:
            sys.exit(1)

    elif args.command == "sync":
        mgr.sync(env=args.env)

    elif args.command == "audit":
        if not mgr.audit():
            sys.exit(1)

    elif args.command == "report":
        mgr.report()

    elif args.command == "venv":
        mgr.create_venv()


if __name__ == "__main__":
    main()